61	    /// get the actual changed files between two git refs
62	    pub fn changed_files(
63	        &self,
64	        turbo_root: &AbsoluteSystemPath,
65	        from_commit: Option<&str>,
66	        to_commit: Option<&str>,
67	        include_uncommitted: bool,
68	        allow_unknown_objects: bool,
69	        merge_base: bool,
70	    ) -> Result<Result<HashSet<AnchoredSystemPathBuf>, InvalidRange>, Error> {
71	        fn unable_to_detect_range(
72	            error: impl std::error::Error,
73	            from_ref: Option<String>,
74	            to_ref: Option<String>,
75	        ) -> Result<Result<HashSet<AnchoredSystemPathBuf>, InvalidRange>, Error> {
76	            warn!(
77	                "unable to detect git range, assuming all files have changed: {}",
78	                error
79	            );
80	            Ok(Err(InvalidRange { from_ref, to_ref }))
81	        }
82	        match self {
83	            Self::Git(git) => {
84	                match git.changed_files(
85	                    turbo_root,
86	                    from_commit,
87	                    to_commit,
88	                    include_uncommitted,
89	                    merge_base,
90	                ) {
91	                    Ok(files) => Ok(Ok(files)),
92	                    Err(ref error @ Error::Git(ref message, _))
93	                        if allow_unknown_objects
94	                            && (message.contains("no merge base")
95	                                || message.contains("bad object")) =>
96	                    {
97	                        unable_to_detect_range(
98	                            error,
99	                            from_commit.map(|c| c.to_string()),
100	                            to_commit.map(|c| c.to_string()),
101	                        )
102	                    }
103	                    Err(Error::UnableToResolveRef) => unable_to_detect_range(
104	                        Error::UnableToResolveRef,
105	                        from_commit.map(|c| c.to_string()),
106	                        to_commit.map(|c| c.to_string()),
107	                    ),
108	                    Err(e) => Err(e),
109	                }
110	            }
111	            Self::Manual => Err(Error::GitRequired(turbo_root.to_owned())),
112	        }
113	    }
