146	impl GitHubEvent {
147	    fn get_parent_ref_of_first_commit(&self) -> Option<String> {
148	        if self.commits.is_empty() {
149	            // commits can be empty when you push a branch with no commits
150	            return None;
151	        }
152	
153	        if self.commits.len() >= 2048 {
154	            // GitHub API limit for number of commits shown in this field
155	            return None;
156	        }
157	
158	        // Extract the base ref from the push event
159	        let first_commit = self.commits.first()?;
160	        let id = &first_commit.id;
161	        Some(format!("{id}^"))
162	    }
163	}
