208	    /// Compute a hash summarizing all uncommitted state in the working tree.
209	    /// Uses `git status --porcelain -z` (which files are dirty/untracked) and
210	    /// `git diff HEAD` (the actual content changes for tracked files) as inputs
211	    /// to a SHA-256 hash. Returns `None` if the working tree is clean or if
212	    /// git commands fail (with a warning logged).
213	    ///
214	    /// The diff output is streamed through the hasher to avoid buffering
215	    /// arbitrarily large diffs into memory. `--no-ext-diff` and `--no-binary`
216	    /// ensure deterministic, bounded output regardless of user git config.
217	    ///
218	    /// Note: content of untracked files (not yet `git add`ed) is not included
219	    /// in the diff — only their filenames from `git status` contribute.
220	    fn get_dirty_hash(&self) -> Option<String> {
221	        use sha2::{Digest, Sha256};
222	
223	        let status_output = match self.execute_git_command(&["status", "--porcelain", "-z"], "") {
224	            Ok(output) => output,
225	            Err(e) => {
226	                turborepo_log::warn(
227	                    turborepo_log::Source::turbo(turborepo_log::Subsystem::Scm),
228	                    format!("failed to get git status for dirty hash: {e}"),
229	                )
230	                .emit();
231	                return None;
232	            }
233	        };
234	
235	        if status_output.is_empty() {
236	            return None;
237	        }
238	
239	        let mut hasher = Sha256::new();
240	        hasher.update(&status_output);
241	
242	        // Try `git diff HEAD` first. In a freshly initialized repo with no
243	        // commits, HEAD doesn't exist and git exits with code 128. Fall back
244	        // to `git diff --cached` which diffs the index against an empty tree,
245	        // correctly capturing staged file content without needing HEAD.
246	        if !self.stream_diff_into_hasher(
247	            &["diff", "HEAD", "--no-ext-diff", "--no-color"],
248	            &mut hasher,
249	        ) && !self.stream_diff_into_hasher(
250	            &["diff", "--cached", "--no-ext-diff", "--no-color"],
251	            &mut hasher,
252	        ) {
253	            turborepo_log::warn(
254	                turborepo_log::Source::turbo(turborepo_log::Subsystem::Scm),
255	                "failed to run git diff for dirty hash",
256	            )
257	            .emit();
258	        }
259	
260	        Some(hex::encode(hasher.finalize()))
261	    }
262	
263	    /// Spawn a git diff subprocess, streaming its stdout into `hasher`.
264	    /// Returns `true` if the command exited successfully.
265	    fn stream_diff_into_hasher(&self, args: &[&str], hasher: &mut sha2::Sha256) -> bool {
266	        use std::{io::Read, process::Stdio};
267	
268	        use sha2::Digest;
269	
270	        let mut child = match Command::new(self.bin.as_std_path())
271	            .args(args)
272	            .current_dir(&self.root)
273	            .env("GIT_OPTIONAL_LOCKS", "0")
274	            .stdout(Stdio::piped())
275	            .stderr(Stdio::null())
276	            .spawn()
277	        {
278	            Ok(child) => child,
279	            Err(_) => return false,
280	        };
281	
282	        if let Some(stdout) = child.stdout.take() {
283	            let mut reader = std::io::BufReader::new(stdout);
284	            let mut buf = [0u8; 65536];
285	            loop {
286	                match reader.read(&mut buf) {
287	                    Ok(0) => break,
288	                    Ok(n) => hasher.update(&buf[..n]),
289	                    Err(_) => break,
290	                }
291	            }
292	        }
293	
294	        child.wait().is_ok_and(|s| s.success())
295	    }
