297	    /// for GitHub Actions environment variables, see: https://docs.github.com/en/actions/writing-workflows/choosing-what-your-workflow-does/store-information-in-variables#default-environment-variables
298	    pub fn get_github_base_ref(base_ref_env: CIEnv) -> Option<String> {
299	        // make sure we're running in a CI environment
300	        if !base_ref_env.is_github_actions {
301	            return None;
302	        }
303	
304	        /*
305	         * The name of the base ref or target branch of the pull request in a
306	         * workflow run.
307	         *
308	         * This variable only has a value when the event that triggers a workflow run
309	         * is either `pull_request` or `pull_request_target`.
310	         * For example, `main`
311	         *
312	         * So environment variable is empty in a regular commit
313	         */
314	        if let Ok(pr) = base_ref_env.github_base_ref
315	            && !pr.is_empty()
316	        {
317	            return Some(pr);
318	        }
319	
320	        // we must be in a push event
321	        // try reading from the GITHUB_EVENT_PATH file
322	        if let Ok(event_path) = base_ref_env.github_event_path {
323	            // Try to open the event file and read the contents
324	            let data = fs::read_to_string(event_path).ok()?;
325	
326	            // Parse the JSON data from the file
327	            let json: GitHubEvent = serde_json::from_str(&data).ok()?;
328	
329	            // Extract the base ref from the pull request event if available
330	            let base_ref = &json.before;
331	
332	            // the base_ref will be UNKNOWN_SHA on first push
333	            // we also use this behavior in force pushes
334	            if base_ref == UNKNOWN_SHA || json.forced {
335	                return json.get_parent_ref_of_first_commit();
336	            }
337	
338	            if base_ref.is_empty() {
339	                return None;
340	            }
341	
342	            return Some(base_ref.to_string());
343	        }
344	        None
345	    }
