347	    fn resolve_base(&self, base_override: Option<&str>, env: CIEnv) -> Result<String, Error> {
348	        if let Some(valid_from) = base_override {
349	            return Ok(valid_from.to_string());
350	        }
351	
352	        if let Some(github_base_ref) = Self::get_github_base_ref(env) {
353	            // we don't fall through to checking against main or master
354	            // because at this point we know we're in a GITHUB CI environment
355	            // and we should really know by now what the base ref is
356	            // so it's better to just error if something went wrong
357	            return match self.execute_git_command(&["rev-parse", &github_base_ref], "") {
358	                Ok(_) => {
359	                    eprintln!("Resolved base ref from GitHub Actions event: {github_base_ref}");
360	                    Ok(github_base_ref)
361	                }
362	                Err(e) => {
363	                    eprintln!(
364	                        "Failed to resolve base ref '{github_base_ref}' from GitHub Actions \
365	                         event: {e}"
366	                    );
367	                    Err(Error::UnableToResolveRef)
368	                }
369	            };
370	        }
371	
372	        let main_result = self.execute_git_command(&["rev-parse", "main"], "");
373	        if main_result.is_ok() {
374	            return Ok("main".to_string());
375	        }
376	
377	        let master_result = self.execute_git_command(&["rev-parse", "master"], "");
378	        if master_result.is_ok() {
379	            return Ok("master".to_string());
380	        }
381	        Err(Error::UnableToResolveRef)
382	    }
