384	    fn changed_files(
385	        &self,
386	        turbo_root: &AbsoluteSystemPath,
387	        from_commit: Option<&str>,
388	        to_commit: Option<&str>,
389	        include_uncommitted: bool,
390	        merge_base: bool,
391	    ) -> Result<HashSet<AnchoredSystemPathBuf>, Error> {
392	        let turbo_root_relative_to_git_root = self.root.anchor(turbo_root)?;
393	        let pathspec = turbo_root_relative_to_git_root.as_str();
394	
395	        let mut files = HashSet::new();
396	
397	        let valid_from = self.resolve_base(from_commit, CIEnv::new())?;
398	
399	        // If a to commit is not specified for `diff-tree` it will change the comparison
400	        // to be between the provided commit and it's parent
401	        let to_commit = to_commit.unwrap_or("HEAD");
402	        let mut args = vec![
403	            "diff-tree",
404	            "-r",
405	            "--name-only",
406	            "--no-commit-id",
407	            "-z",
408	            &valid_from,
409	            to_commit,
410	        ];
411	
412	        if merge_base {
413	            args.push("--merge-base");
414	        }
415	
416	        let output = self.execute_git_command(&args, pathspec)?;
417	        self.add_files_from_stdout(&mut files, turbo_root, output)?;
418	
419	        // We only care about non-tracked files if we haven't specified both ends up the
420	        // comparison
421	        if include_uncommitted {
422	            // Add untracked files or unstaged changes, i.e. files that are not in git at
423	            // all
424	            let ls_files_output = self.execute_git_command(
425	                &[
426	                    "ls-files",
427	                    "--others",
428	                    "--modified",
429	                    "--exclude-standard",
430	                    "-z",
431	                ],
432	                pathspec,
433	            )?;
434	            self.add_files_from_stdout(&mut files, turbo_root, ls_files_output)?;
435	            // Include any files that have been staged, but not committed
436	            let diff_output =
437	                self.execute_git_command(&["diff", "--name-only", "--cached", "-z"], pathspec)?;
438	            self.add_files_from_stdout(&mut files, turbo_root, diff_output)?;
439	        }
440	
441	        Ok(files)
442	    }
