444	    pub fn execute_git_command(&self, args: &[&str], pathspec: &str) -> Result<Vec<u8>, Error> {
445	        let mut command = Command::new(self.bin.as_std_path());
446	        command
447	            .args(args)
448	            .current_dir(&self.root)
449	            .env("GIT_OPTIONAL_LOCKS", "0");
450	
451	        if !pathspec.is_empty() {
452	            command.arg("--").arg(pathspec);
453	        }
454	
455	        let output = command.output()?;
456	
457	        if !output.status.success() {
458	            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
459	            Err(Error::Git(stderr, Backtrace::capture()))
460	        } else {
461	            Ok(output.stdout)
462	        }
463	    }
464	
465	    fn add_files_from_stdout(
466	        &self,
467	        files: &mut HashSet<AnchoredSystemPathBuf>,
468	        turbo_root: &AbsoluteSystemPath,
469	        stdout: Vec<u8>,
470	    ) -> Result<(), Error> {
471	        let stdout = String::from_utf8_lossy(&stdout);
472	        for line in stdout.split('\0') {
473	            if line.is_empty() {
474	                continue;
475	            }
476	            let path = RelativeUnixPath::new(line)?;
477	            let anchored_to_turbo_root_file_path =
478	                self.reanchor_path_from_git_root_to_turbo_root(turbo_root, path)?;
479	            files.insert(anchored_to_turbo_root_file_path);
480	        }
481	        Ok(())
482	    }
483	
484	    fn reanchor_path_from_git_root_to_turbo_root(
485	        &self,
486	        turbo_root: &AbsoluteSystemPath,
487	        path: &RelativeUnixPath,
488	    ) -> Result<AnchoredSystemPathBuf, Error> {
489	        let absolute_file_path = self.root.join_unix_path(path);
490	        let anchored_to_turbo_root_file_path = turbo_root.anchor(&absolute_file_path)?;
491	        Ok(anchored_to_turbo_root_file_path)
492	    }
