494	    fn previous_content(
495	        &self,
496	        from_commit: Option<&str>,
497	        file_path: &AbsoluteSystemPath,
498	    ) -> Result<Vec<u8>, Error> {
499	        let anchored_file_path = self.root.anchor(file_path)?;
500	        let valid_from = self.resolve_base(from_commit, CIEnv::new())?;
501	        let arg = format!("{}:{}", valid_from, anchored_file_path.as_str());
502	
503	        self.execute_git_command(&["show", &arg], "")
504	    }
505	}
