507	/// Finds the content of a file at a previous commit. Assumes file is in a git
508	/// repository
509	///
510	/// # Arguments
511	///
512	/// * `git_root`: The root of the repository
513	/// * `from_commit`: The commit hash to checkout
514	/// * `file_path`: The path to the file
515	///
516	/// returns: Result<String, Error>
517	pub fn previous_content(
518	    git_root: PathBuf,
519	    from_commit: Option<&str>,
520	    file_path: String,
521	) -> Result<Vec<u8>, Error> {
522	    // If git root is not absolute, we error.
523	    let git_root = AbsoluteSystemPathBuf::try_from(git_root)?;
524	    let scm = SCM::new(&git_root);
525	
526	    // However for file path we handle both absolute and relative paths
527	    // Note that we assume any relative file path is relative to the git root
528	    // FIXME: this is probably wrong. We should know the path to the lockfile
529	    // exactly
530	    let absolute_file_path = AbsoluteSystemPathBuf::from_unknown(&git_root, file_path);
531	
532	    scm.previous_content(from_commit, &absolute_file_path)
533	}
