557	    fn run_git(repo_root: &Path, args: &[&str]) -> String {
558	        let output = Command::new("git")
559	            .args(args)
560	            .current_dir(repo_root)
561	            .env("GIT_AUTHOR_NAME", "test")
562	            .env("GIT_AUTHOR_EMAIL", "test@test.com")
563	            .env("GIT_COMMITTER_NAME", "test")
564	            .env("GIT_COMMITTER_EMAIL", "test@test.com")
565	            .output()
566	            .unwrap();
567	        assert!(
568	            output.status.success(),
569	            "git {:?} failed: {}",
570	            args,
571	            String::from_utf8_lossy(&output.stderr)
572	        );
573	        String::from_utf8(output.stdout).unwrap().trim().to_string()
574	    }
