577	        let repo_root = tempfile::tempdir()?;
578	        run_git(repo_root.path(), &["init"]);
579	        if let Some(branch) = initial_head {
580	            run_git(
581	                repo_root.path(),
582	                &["symbolic-ref", "HEAD", &format!("refs/heads/{}", branch)],
583	            );
584	        }
585	        run_git(repo_root.path(), &["config", "user.name", "test"]);
586	        run_git(
587	            repo_root.path(),
588	            &["config", "user.email", "test@example.com"],
589	        );
590	
