595	    fn changed_files(
596	        git_root: PathBuf,
597	        turbo_root: PathBuf,
598	        from_commit: Option<&str>,
599	        to_commit: Option<&str>,
600	        include_uncommitted: bool,
601	    ) -> Result<HashSet<String>, Error> {
602	        let git_root = AbsoluteSystemPath::from_std_path(&git_root)?;
603	        let scm = SCM::new(git_root);
604	
605	        let turbo_root = AbsoluteSystemPathBuf::try_from(turbo_root.as_path())?;
606	        // Replicating the `--filter` behavior where we only do a merge base
607	        // if both ends of the git range are specified.
608	        let merge_base = to_commit.is_some();
609	        let Ok(files) = scm.changed_files(
610	            &turbo_root,
611	            from_commit,
612	            to_commit,
613	            include_uncommitted,
614	            false,
615	            merge_base,
616	        )?
617	        else {
618	            unreachable!("changed_files should always return Some");
619	        };
620	
621	        Ok(files
622	            .into_iter()
623	            .map(|f| f.to_string())
624	            .collect::<HashSet<_>>())
625	    }
