822	
823	        // Test that uncommitted file in index is not marked as changed when not
824	        // checking uncommitted
825	        let files = changed_files(
826	            repo_root.path().to_path_buf(),
827	            turbo_root.to_path_buf(),
828	            Some("HEAD"),
829	            None,
830	            false,
831	        )?;
832	        assert_eq!(files, HashSet::new());
833	
834	        // Test that uncommitted file in index is marked as changed when
835	        // checking uncommitted
836	        let files = changed_files(
837	            repo_root.path().to_path_buf(),
838	            turbo_root.to_path_buf(),
839	            Some("HEAD"),
840	            None,
841	            true,
842	        )?;
843	        assert_eq!(files, HashSet::from(["bar.js".to_string()]));
844	
845	        // Add file to index
846	        run_git(&repo_path, &["add", "bar.js"]);
847	
848	        // Test that uncommitted file in index is not marked as changed when not
849	        // checking uncommitted
850	        let files = changed_files(
851	            repo_root.path().to_path_buf(),
852	            turbo_root.to_path_buf(),
853	            Some("HEAD"),
854	            None,
855	            false,
856	        )?;
857	        assert_eq!(files, HashSet::new());
858	
859	        // Test that uncommitted file in index is still marked as changed
860	        let files = changed_files(
861	            repo_root.path().to_path_buf(),
862	            turbo_root.to_path_buf(),
863	            Some("HEAD"),
864	            None,
865	            true,
866	        )?;
867	        assert_eq!(files, HashSet::from(["bar.js".to_string()]));
868	
869	        // Now commit file
870	        let second_commit_sha =
871	            commit_file(&repo_path, Path::new("bar.js"), Some(&first_commit_sha));
872	
873	        // Test that only second file is marked as changed when we check commit range
874	        let files = changed_files(
875	            repo_root.path().to_path_buf(),
876	            turbo_root.to_path_buf(),
877	            Some(first_commit_sha.as_str()),
878	            Some(second_commit_sha.as_str()),
879	            false,
880	        )?;
881	        assert_eq!(files, HashSet::from(["bar.js".to_string()]));
882	
883	        // Create a file nested in subdir
884	        fs::create_dir_all(repo_root.path().join("subdir"))?;
885	        let new_file = repo_root.path().join("subdir").join("baz.js");
886	        fs::write(new_file, "let x = 2;")?;
