2	//!
3	//! This module handles --filter flag parsing and package filtering.
4	
5	use std::{
6	    collections::{HashMap, HashSet},
7	    path::Path,
8	    str::FromStr,
9	};
10	
11	use miette::Diagnostic;
12	use tracing::debug;
13	use turbopath::{AbsoluteSystemPath, AbsoluteSystemPathBuf, AnchoredSystemPathBuf};
14	use turborepo_repository::{
15	    change_mapper::{ChangeMapError, PackageInclusionReason, merge_changed_packages},
16	    package_graph::{self, PackageGraph, PackageName},
17	};
18	use turborepo_scm::SCM;
19	use turborepo_types::FilterMode;
20	use wax::Program;
21	
22	use crate::{
23	    ScopeOpts,
24	    change_detector::{GitChangeDetector, ScopeChangeDetector},
25	    simple_glob::{Match, SimpleGlob},
26	    target_selector::{GitRange, InvalidSelectorError, TargetSelector},
27	};
28	
29	/// Package inference for directory-based filtering.
30	pub struct PackageInference {
31	    package_name: Option<String>,
32	    directory_root: AnchoredSystemPathBuf,
33	}
34	
35	impl PackageInference {
36	    // calculate, based on the directory that global turbo was invoked in,
37	    // the pieces of a filter spec that we will infer. If turbo was invoked
38	    // somewhere between the root and packages, scope turbo invocations to the
39	    // packages below where turbo was invoked. If turbo was invoked at or within
40	    // a particular package, scope the turbo invocation to just that package.
41	    pub fn calculate(
42	        turbo_root: &AbsoluteSystemPath,
43	        pkg_inference_path: &AnchoredSystemPathBuf,
44	        pkg_graph: &PackageGraph,
45	    ) -> Self {
46	        debug!(
47	            "Using {} as a basis for selecting packages",
48	            pkg_inference_path
49	        );
50	        let full_inference_path = turbo_root.resolve(pkg_inference_path);
51	
52	        // Track the best matching package (the one whose path is the longest prefix
53	        // of the inference path, i.e., the most specific package containing our
54	        // current directory)
55	        let mut best_match: Option<(String, AnchoredSystemPathBuf)> = None;
56	        let mut found_package_below = false;
57	
58	        for (workspace_name, workspace_entry) in pkg_graph.packages() {
59	            let pkg_path = turbo_root.resolve(workspace_entry.package_path());
60	
61	            // Check if the inference path is inside this package (pkg_path is a prefix of
62	            // full_inference_path)
63	            let inferred_path_is_below = pkg_path.contains(&full_inference_path);
64	
65	            // We skip over the root package as the inferred path will always be below it
66	            if inferred_path_is_below && (&pkg_path as &AbsoluteSystemPath) != turbo_root {
67	                // This package contains the inference path. Track it if it's a better
68	                // (longer/more specific) match than what we've found so far.
69	                let pkg_path_len = workspace_entry.package_path().as_str().len();
70	                let is_better_match = match &best_match {
71	                    None => true,
72	                    Some((_, existing_path)) => pkg_path_len > existing_path.as_str().len(),
73	                };
74	
75	                if is_better_match {
76	                    best_match = Some((
77	                        workspace_name.to_string(),
78	                        workspace_entry.package_path().to_owned(),
79	                    ));
80	                }
81	            }
82	
83	            // Check if this package is below the inference path (full_inference_path is a
84	            // prefix of pkg_path)
85	            let inferred_path_is_between_root_and_pkg = full_inference_path.contains(&pkg_path);
86	            if inferred_path_is_between_root_and_pkg {
87	                // We've found *some* package below our inference directory
88	                found_package_below = true;
89	            }
90	        }
91	
92	        // If we found a package that contains our inference path, use it
93	        if let Some((package_name, directory_root)) = best_match {
94	            return Self {
95	                package_name: Some(package_name),
96	                directory_root,
97	            };
98	        }
99	
100	        // If we found packages below the inference path, or no packages matched at all,
101	        // use the inference path as the directory root
102	        if found_package_below {
103	            // We're in a directory that contains packages
104	        }
105	
106	        Self {
107	            package_name: None,
108	            directory_root: pkg_inference_path.to_owned(),
109	        }
110	    }
111	
112	    pub fn apply(&self, selector: &mut TargetSelector) {
113	        // if the name pattern is provided, do not attempt inference
114	        if !selector.name_pattern.is_empty() {
115	            return;
116	        };
117	
118	        // Inject package name based on the directory filter:
119	        // - No filter: inject name (original behavior)
120	        // - Filter navigates up (starts with ".."): inject name (backwards compat)
121	        // - Filter stays within current dir (e.g., "./*"): don't inject name because
122	        //   user is explicitly selecting child packages
123	        if let Some(name) = &self.package_name {
124	            let should_inject_name = match selector.parent_dir.as_deref() {
125	                None => true,
126	                Some(parent_dir) => parent_dir.as_str().starts_with(".."),
127	            };
128	            if should_inject_name {
129	                selector.name_pattern.clone_from(name);
130	            }
131	        }
132	
133	        if let Some(parent_dir) = selector.parent_dir.as_deref() {
134	            let repo_relative_parent_dir = self.directory_root.join(parent_dir);
135	            let clean_parent_dir = path_clean::clean(Path::new(repo_relative_parent_dir.as_path()))
136	                .into_os_string()
137	                .into_string()
138	                .expect("path was valid utf8 before cleaning");
139	            selector.parent_dir = Some(
140	                AnchoredSystemPathBuf::try_from(clean_parent_dir.as_str())
141	                    .expect("path wasn't absolute before cleaning"),
142	            );
143	        } else if self.package_name.is_none() {
144	            // fallback: the user didn't set a parent directory and we didn't find a single
145	            // package, so use the directory we inferred and select all subdirectories
146	            let mut parent_dir = self.directory_root.clone();
147	            parent_dir.push("**");
148	            selector.parent_dir = Some(parent_dir);
149	        }
150	    }
151	}
