188	impl<'a, T: GitChangeDetector> FilterResolver<'a, T> {
189	    pub fn new_with_change_detector(
190	        pkg_graph: &'a PackageGraph,
191	        turbo_root: &'a AbsoluteSystemPath,
192	        inference: Option<PackageInference>,
193	        change_detector: T,
194	    ) -> Self {
195	        Self {
196	            pkg_graph,
197	            turbo_root,
198	            inference,
199	            change_detector,
200	        }
201	    }
202	
203	    /// Resolve the set of packages matching the given filter patterns.
204	    ///
205	    /// Returns the matched packages alongside a [`FilterMode`] that
206	    /// describes the kind of filter that was applied. The caller uses
207	    /// `FilterMode` to decide whether root tasks should be injected
208	    /// without re-parsing raw filter strings.
209	    ///
210	    /// Root (`//`) is never included in the returned package set — the
211	    /// caller is responsible for adding it when appropriate (see
212	    /// `RunBuilder::calculate_filtered_packages`).
213	    pub fn resolve(
214	        &self,
215	        affected: &Option<(Option<String>, Option<String>)>,
216	        patterns: &[String],
217	    ) -> Result<(HashMap<PackageName, PackageInclusionReason>, FilterMode), ResolutionError> {
218	        let is_all_packages = patterns.is_empty() && self.inference.is_none() && affected.is_none();
219	
220	        if is_all_packages {
221	            let packages = self
222	                .pkg_graph
223	                .packages()
224	                .filter(|(name, _)| matches!(name, PackageName::Other(_)))
225	                .map(|(name, _)| {
226	                    (
227	                        name.to_owned(),
228	                        PackageInclusionReason::IncludedByFilter {
229	                            filters: patterns.to_vec(),
230	                        },
231	                    )
232	                })
233	                .collect();
234	            return Ok((packages, FilterMode::AllPackages));
235	        }
236	
237	        // Parse selectors once — reused for both mode classification and resolution.
238	        let selectors: Vec<TargetSelector> = patterns
239	            .iter()
240	            .map(|pattern| TargetSelector::from_str(pattern))
241	            .collect::<Result<Vec<_>, _>>()?;
242	
243	        let mode = self.classify_filter_mode(&selectors, affected);
244	
245	        let affected_selector = affected.as_ref().map(|(from_ref, to_ref)| TargetSelector {
246	            git_range: Some(GitRange {
247	                from_ref: from_ref.clone(),
248	                to_ref: to_ref.clone(),
249	                include_uncommitted: true,
250	                allow_unknown_objects: true,
251	                merge_base: true,
252	            }),
253	            include_dependents: true,
254	            ..Default::default()
255	        });
256	
257	        if let Some(affected_sel) = affected_selector {
258	            if selectors.is_empty() {
259	                let packages = self.get_filtered_packages(vec![affected_sel])?;
260	                return Ok((packages, mode));
261	            }
262	
263	            let affected_pkgs = self.get_filtered_packages(vec![affected_sel])?;
264	
265	            // Explicit include/exclude ordering that mirrors task_filter.rs:
266	            //   (filter_includes ∩ affected) - filter_excludes
267	            let (include_sels, exclude_sels): (Vec<_>, Vec<_>) =
268	                selectors.into_iter().partition(|s| !s.exclude);
269	
270	            let included = if include_sels.is_empty() {
271	                // No include selectors → start from full affected set
272	                affected_pkgs
273	            } else {
274	                let filter_pkgs = self.get_filtered_packages(include_sels)?;
275	                filter_pkgs
276	                    .into_iter()
277	                    .filter(|(name, _)| affected_pkgs.contains_key(name))
278	                    .collect()
279	            };
280	
281	            if exclude_sels.is_empty() {
282	                return Ok((included, mode));
283	            }
284	
285	            // Resolve exclude selectors to the set of package names to subtract.
286	            // Flip the exclude flag so filter_graph resolves them as normal
287	            // includes — we just need the matching package names.
288	            let exclude_names: HashSet<PackageName> = {
289	                let as_includes: Vec<_> = exclude_sels
290	                    .into_iter()
291	                    .map(|mut s| {
292	                        s.exclude = false;
293	                        s
294	                    })
295	                    .collect();
296	                self.get_filtered_packages(as_includes)?
297	                    .into_keys()
298	                    .collect()
299	            };
300	
301	            let packages = included
302	                .into_iter()
303	                .filter(|(name, _)| !exclude_names.contains(name))
304	                .collect();
305	
306	            return Ok((packages, mode));
307	        }
308	
309	        let packages = self.get_filtered_packages(selectors)?;
310	        Ok((packages, mode))
311	    }
312	
313	    /// Classify the filter mode from parsed selectors.
314	    ///
315	    /// Only patterns from the CLI are considered — affected ranges and
316	    /// package inference are separate selection mechanisms that always
317	    /// produce an explicit selection.
318	    fn classify_filter_mode(
319	        &self,
320	        pattern_selectors: &[TargetSelector],
321	        affected: &Option<(Option<String>, Option<String>)>,
322	    ) -> FilterMode {
323	        if self.inference.is_some() || affected.is_some() || pattern_selectors.is_empty() {
324	            return FilterMode::ExplicitSelection;
325	        }
326	
327	        if pattern_selectors.iter().all(|s| s.exclude) {
328	            let root_excluded = pattern_selectors
329	                .iter()
330	                .any(|s| Self::selector_matches_root(s));
331	            FilterMode::ExcludeOnly { root_excluded }
332	        } else {
333	            FilterMode::ExplicitSelection
334	        }
335	    }
336	
337	    /// Check whether a selector would match the root package.
338	    ///
339	    /// Uses the same glob matching as `match_package_names` for name
340	    /// patterns, and checks `parent_dir` for the repo root directory.
341	    fn selector_matches_root(selector: &TargetSelector) -> bool {
342	        if !selector.name_pattern.is_empty()
343	            && let Ok(matcher) = SimpleGlob::new(&selector.name_pattern)
344	            && matcher.is_match(PackageName::Root.as_ref())
345	        {
346	            return true;
347	        }
348	
349	        if let Some(ref parent_dir) = selector.parent_dir {
350	            let dir_str = parent_dir.as_str();
351	            if dir_str == "." || dir_str.is_empty() {
352	                return true;
353	            }
354	        }
355	
356	        false
357	    }
358	
359	    fn get_filtered_packages(
360	        &self,
361	        selectors: Vec<TargetSelector>,
362	    ) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
363	        let (_prod_selectors, all_selectors) = self
364	            .apply_inference(selectors)
365	            .into_iter()
366	            .partition::<Vec<_>, _>(|t| t.follow_prod_deps_only);
367	
368	        if !all_selectors.is_empty() {
369	            self.filter_graph(all_selectors)
370	        } else {
371	            Ok(Default::default())
372	        }
373	    }
374	
375	    fn apply_inference(&self, selectors: Vec<TargetSelector>) -> Vec<TargetSelector> {
376	        let inference = match self.inference {
377	            Some(ref inference) => inference,
378	            None => return selectors,
379	        };
380	
381	        // if there is no selector provided, synthesize one
382	        let mut selectors = if selectors.is_empty() {
383	            vec![Default::default()]
384	        } else {
385	            selectors
386	        };
387	
388	        for selector in &mut selectors {
389	            inference.apply(selector);
390	        }
391	
392	        selectors
393	    }
394	
395	    fn filter_graph(
396	        &self,
397	        selectors: Vec<TargetSelector>,
398	    ) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
399	        let (include_selectors, exclude_selectors) =
400	            selectors.into_iter().partition::<Vec<_>, _>(|t| !t.exclude);
401	
402	        let mut include = if !include_selectors.is_empty() {
403	            // TODO: add telemetry for each selector
404	            self.filter_graph_with_selectors(include_selectors)?
405	        } else {
406	            self.pkg_graph
407	                .packages()
408	                // todo: a type-level way of dealing with non-root packages
409	                .filter(|(name, _)| !PackageName::Root.eq(name)) // the root package has to be explicitly included
410	                .map(|(name, _)| {
411	                    (
412	                        name.to_owned(),
413	                        PackageInclusionReason::IncludedByFilter {
414	                            filters: exclude_selectors
415	                                .iter()
416	                                .map(|s| s.raw.to_string())
417	                                .collect(),
418	                        },
419	                    )
420	                })
421	                .collect()
422	        };
423	
424	        // We want to just collect the names, not the reasons, so when we check for
425	        // inclusion we don't need to check the reason
426	        let exclude: HashSet<PackageName> = self
427	            .filter_graph_with_selectors(exclude_selectors)?
428	            .into_keys()
429	            .collect();
430	
431	        include.retain(|i, _| !exclude.contains(i));
432	
433	        Ok(include)
434	    }
435	
436	    fn filter_graph_with_selectors(
437	        &self,
438	        selectors: Vec<TargetSelector>,
439	    ) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
440	        let mut unmatched_selectors = Vec::new();
441	        let mut walked_dependencies = HashMap::new();
442	        let mut walked_dependents = HashMap::new();
443	        let mut walked_dependent_dependencies = HashMap::new();
444	        let mut cherry_picked_packages = HashMap::new();
445	
446	        for selector in selectors {
447	            let selector_packages = self.filter_graph_with_selector(&selector)?;
448	
449	            if selector_packages.is_empty() {
450	                unmatched_selectors.push(selector);
451	                continue;
452	            }
453	
454	            for (package, reason) in selector_packages {
455	                let node = package_graph::PackageNode::Workspace(package.clone());
456	
457	                if selector.include_dependencies {
458	                    let dependencies = self.pkg_graph.dependencies(&node);
459	                    let dependencies = dependencies
460	                        .iter()
461	                        .filter(|node| !matches!(node, package_graph::PackageNode::Root))
462	                        .map(|i| {
463	                            (
464	                                i.as_package_name().to_owned(),
465	                                // While we're adding dependencies, from their
466	                                // perspective, they were changed because
467	                                // of a *dependent*
468	                                PackageInclusionReason::DependentChanged {
469	                                    dependent: package.to_owned(),
470	                                },
471	                            )
472	                        })
473	                        .collect::<Vec<_>>();
474	
475	                    // flatmap through the option, the set, and then the optional package name
476	                    merge_changed_packages(&mut walked_dependencies, dependencies);
477	                }
478	
479	                if selector.include_dependents {
480	                    let dependents = self.pkg_graph.ancestors(&node);
481	                    for dependent in dependents.iter().map(|i| i.as_package_name()) {
482	                        walked_dependents.insert(
483	                            dependent.clone(),
484	                            // While we're adding dependents, from their
485	                            // perspective, they were changed because
486	                            // of a *dependency*
487	                            PackageInclusionReason::DependencyChanged {
488	                                dependency: package.to_owned(),
489	                            },
490	                        );
491	
492	                        // get the dependent's dependencies
493	                        if selector.include_dependencies {
494	                            let dependent_node =
495	                                package_graph::PackageNode::Workspace(dependent.to_owned());
496	
497	                            let dependent_dependencies =
498	                                self.pkg_graph.dependencies(&dependent_node);
499	
500	                            let dependent_dependencies = dependent_dependencies
501	                                .iter()
502	                                .filter(|node| !matches!(node, package_graph::PackageNode::Root))
503	                                .map(|i| {
504	                                    (
505	                                        i.as_package_name().to_owned(),
506	                                        PackageInclusionReason::DependencyChanged {
507	                                            dependency: package.to_owned(),
508	                                        },
509	                                    )
510	                                })
511	                                .collect::<HashSet<_>>();
512	
513	                            merge_changed_packages(
514	                                &mut walked_dependent_dependencies,
515	                                dependent_dependencies,
516	                            );
517	                        }
518	                    }
519	                }
520	
521	                if (selector.include_dependents || selector.include_dependencies)
522	                    && !selector.exclude_self
523	                {
524	                    // if we are including dependents or dependencies, and we are not excluding
525	                    // ourselves, then we should add ourselves to the list of packages
526	                    walked_dependencies.insert(package, reason);
527	                } else if !selector.include_dependencies && !selector.include_dependents {
528	                    // if we are neither including dependents or dependencies, then
529	                    // add  to the list of cherry picked packages
530	                    cherry_picked_packages.insert(package, reason);
531	                }
532	            }
533	        }
534	
535	        let mut all_packages = HashMap::new();
536	        merge_changed_packages(&mut all_packages, walked_dependencies);
537	        merge_changed_packages(&mut all_packages, walked_dependents);
538	        merge_changed_packages(&mut all_packages, walked_dependent_dependencies);
539	        merge_changed_packages(&mut all_packages, cherry_picked_packages);
540	
541	        Ok(all_packages)
542	    }
543	
544	    fn filter_graph_with_selector(
545	        &self,
546	        selector: &TargetSelector,
547	    ) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
548	        if selector.match_dependencies {
549	            self.filter_subtrees_with_selector(selector)
550	        } else {
551	            self.filter_nodes_with_selector(selector)
552	        }
553	    }
554	
555	    /// returns the set of nodes where the node or any of its dependencies match
556	    /// the selector.
557	    ///
558	    /// Example:
559	    /// a -> b -> c
560	    /// a -> d
561	    ///
562	    /// filter(b) = {a, b, c}
563	    /// filter(d) = {a, d}
564	    fn filter_subtrees_with_selector(
565	        &self,
566	        selector: &TargetSelector,
567	    ) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
568	        let mut entry_packages = HashMap::new();
569	
570	        // Compile glob pattern ONCE outside the loop to avoid O(n) compilation overhead
571	        let parent_dir_matcher = selector
572	            .parent_dir
573	            .as_deref()
574	            .map(|parent_dir| {
575	                let path = parent_dir.to_unix();
576	                wax::Glob::new(path.as_str()).map(wax::Glob::into_owned)
577	            })
578	            .transpose()?;
579	
580	        for (name, info) in self.pkg_graph.packages() {
581	            if let Some(ref matcher) = parent_dir_matcher {
582	                let matches = matcher.is_match(info.package_path().as_path());
583	
584	                if matches {
585	                    entry_packages.insert(
586	                        name.to_owned(),
587	                        PackageInclusionReason::InFilteredDirectory {
588	                            directory: selector.parent_dir.as_ref().unwrap().to_owned(),
589	                        },
590	                    );
591	                }
592	            } else {
593	                entry_packages.insert(
594	                    name.to_owned(),
595	                    PackageInclusionReason::IncludedByFilter {
596	                        filters: vec![selector.raw.to_string()],
597	                    },
598	                );
599	            }
600	        }
601	
602	        // if we have a filter, use it to filter the entry packages
603	        let filtered_entry_packages = if !selector.name_pattern.is_empty() {
604	            match_package_names(&selector.name_pattern, &self.all_packages(), entry_packages)?
605	        } else {
606	            entry_packages
607	        };
608	
609	        let mut roots = HashMap::new();
610	        let mut matched = HashSet::new();
611	        let changed_packages = if let Some(git_range) = selector.git_range.as_ref() {
612	            self.packages_changed_in_range(git_range)?
613	        } else {
614	            HashMap::default()
615	        };
616	
617	        for (package, reason) in filtered_entry_packages {
618	            if matched.contains(&package) {
619	                roots.insert(package, reason);
620	                continue;
621	            }
622	
623	            let workspace_node = package_graph::PackageNode::Workspace(package.clone());
624	            let dependencies = self.pkg_graph.dependencies(&workspace_node);
625	
626	            for changed_package in changed_packages.keys() {
627	                if !selector.exclude_self && package.eq(changed_package) {
628	                    roots.insert(package, reason);
629	                    break;
630	                }
631	
632	                let changed_node =
633	                    package_graph::PackageNode::Workspace(changed_package.to_owned());
634	
635	                if dependencies.contains(&changed_node) {
636	                    roots.insert(package.clone(), reason);
637	                    matched.insert(package);
638	                    break;
639	                }
640	            }
641	        }
642	
643	        Ok(roots)
644	    }
645	
646	    fn filter_nodes_with_selector(
647	        &self,
648	        selector: &TargetSelector,
649	    ) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
650	        let mut entry_packages = HashMap::new();
651	        let mut selector_valid = false;
652	
653	        let parent_dir_unix = selector.parent_dir.as_deref().map(|path| path.to_unix());
654	        let parent_dir_globber = parent_dir_unix
655	            .as_deref()
656	            .map(|path| {
657	                wax::Glob::new(path.as_str()).map_err(|err| ResolutionError::InvalidDirectoryGlob {
658	                    glob: path.as_str().to_string(),
659	                    err: Box::new(err),
660	                })
661	            })
662	            .transpose()?;
663	
664	        if let Some(globber) = parent_dir_globber.clone() {
665	            let (base, _) = globber.partition();
666	            // wax takes a unix-like glob, but partition will return a system path
667	            // TODO: it would be more proper to use
668	            // `AnchoredSystemPathBuf::from_system_path` but that function
669	            // doesn't allow leading `.` or `..`.
670	            let base = AnchoredSystemPathBuf::from_raw(
671	                base.to_str().expect("glob base should be valid utf8"),
672	            )
673	            .expect("partitioned glob gave absolute path");
674	            // need to join this with globbing's current dir :)
675	            let path = self.turbo_root.resolve(&base);
676	            if !path.exists() {
677	                return Err(ResolutionError::DirectoryDoesNotExist(path));
678	            }
679	        }
680	
681	        if let Some(git_range) = selector.git_range.as_ref() {
682	            selector_valid = true;
683	            let changed_packages = self.packages_changed_in_range(git_range)?;
684	            let package_path_lookup = self
685	                .pkg_graph
686	                .packages()
687	                .map(|(name, entry)| (name, entry.package_path()))
688	                .collect::<HashMap<_, _>>();
689	
690	            for (package, reason) in changed_packages {
691	                if let Some(parent_dir_globber) = parent_dir_globber.as_ref() {
692	                    if package == PackageName::Root {
693	                        // The root package changed, only add it if
694	                        // the parentDir is equivalent to the root
695	                        if parent_dir_globber.matched(&Path::new(".").into()).is_some() {
696	                            entry_packages.insert(package, reason);
697	                        }
698	                    } else {
699	                        let path = package_path_lookup
700	                            .get(&package)
701	                            .ok_or(ResolutionError::MissingPackageInfo(package.to_string()))?;
702	
703	                        if parent_dir_globber.is_match(path.as_path()) {
704	                            entry_packages.insert(package, reason);
705	                        }
706	                    }
707	                } else {
708	                    entry_packages.insert(package, reason);
709	                }
710	            }
711	        } else if let Some((parent_dir, parent_dir_globber)) = selector
712	            .parent_dir
713	            .as_deref()
714	            .zip(parent_dir_globber.as_ref())
715	        {
716	            selector_valid = true;
717	            if parent_dir == &*AnchoredSystemPathBuf::from_raw(".").expect("valid anchored") {
718	                entry_packages.insert(
719	                    PackageName::Root,
720	                    PackageInclusionReason::InFilteredDirectory {
721	                        directory: parent_dir.to_owned(),
722	                    },
723	                );
724	            } else {
725	                let packages = self.pkg_graph.packages();
726	                for (name, _) in packages.filter(|(_name, info)| {
727	                    let path = info.package_path().as_path();
728	                    parent_dir_globber.is_match(path)
729	                }) {
730	                    entry_packages.insert(
731	                        name.to_owned(),
732	                        PackageInclusionReason::InFilteredDirectory {
733	                            directory: parent_dir.to_owned(),
734	                        },
735	                    );
736	                }
737	            }
738	        }
739	
740	        if !selector.name_pattern.is_empty() {
741	            if !selector_valid {
742	                entry_packages = self
743	                    .all_packages()
744	                    .into_iter()
745	                    .map(|name| {
746	                        (
747	                            name,
748	                            PackageInclusionReason::IncludedByFilter {
749	                                filters: vec![selector.raw.to_string()],
750	                            },
751	                        )
752	                    })
753	                    .collect();
754	                selector_valid = true;
755	            }
756	            let all_packages = self.all_packages();
757	            entry_packages =
758	                match_package_names(&selector.name_pattern, &all_packages, entry_packages)?;
759	        }
760	
761	        // if neither a name pattern, parent dir, or from ref is provided, then
762	        // the selector is invalid
763	        if !selector_valid {
764	            Err(ResolutionError::InvalidSelector(
765	                InvalidSelectorError::InvalidSelector(selector.raw.clone()),
766	            ))
767	        } else {
768	            Ok(entry_packages)
769	        }
770	    }
