796	/// match the provided name pattern against the provided set of packages
797	/// and return the set of packages that match the pattern
798	///
799	/// the pattern is normalized, replacing `\*` with `.*`
800	fn match_package_names(
801	    name_pattern: &str,
802	    all_packages: &HashSet<PackageName>,
803	    mut packages: HashMap<PackageName, PackageInclusionReason>,
804	) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
805	    let matcher = SimpleGlob::new(name_pattern)?;
806	    let matched_packages = all_packages
807	        .iter()
808	        .filter(|e| matcher.is_match(e.as_ref()))
809	        .cloned()
810	        .collect::<HashSet<_>>();
811	
812	    // If the pattern was an exact name and it matched no packages, then error
813	    if matcher.is_exact() && matched_packages.is_empty() {
814	        return Err(ResolutionError::NoPackagesMatchedWithName(
815	            name_pattern.to_owned(),
816	        ));
817	    }
818	
819	    packages.retain(|pkg, _| matched_packages.contains(pkg));
820	
821	    Ok(packages)
822	}
