826	pub enum ResolutionError {
827	    #[error("missing info for package")]
828	    MissingPackageInfo(String),
829	    #[error("No packages matched the provided filter")]
830	    NoPackagesMatched,
831	    #[error("Multiple packages matched the provided filter")]
832	    MultiplePackagesMatched,
833	    #[error("The provided filter matched a package that is not in the workspace")]
834	    PackageNotInWorkspace,
835	    #[error("No package found with name '{0}' in workspace")]
836	    NoPackagesMatchedWithName(String),
837	    #[error("selector not used: {0}")]
838	    InvalidSelector(#[from] InvalidSelectorError),
839	    #[error("Invalid regex pattern")]
840	    InvalidRegex(#[from] regex::Error),
841	    #[error("Invalid glob pattern")]
842	    InvalidGlob(#[from] wax::BuildError),
843	    #[error("Unable to query SCM: {0}")]
844	    Scm(#[from] turborepo_scm::Error),
845	    #[error("Unable to calculate changes: {0}")]
846	    ChangeDetectError(#[from] ChangeMapError),
847	    #[error("'Invalid directory filter '{glob}': {err}")]
848	    InvalidDirectoryGlob {
849	        glob: String,
850	        err: Box<wax::BuildError>,
851	    },
852	    #[error("Directory '{0}' specified in filter does not exist")]
853	    DirectoryDoesNotExist(AbsoluteSystemPathBuf),
854	    #[error("failed to construct glob for globalDependencies")]
855	    GlobalDependenciesGlob(#[from] turborepo_repository::change_mapper::Error),
