886	    fn get_name(name: &str) -> (Option<&str>, &str) {
887	        if let Some(idx) = name.rfind('/') {
888	            // check if the rightmost slash has an @
889	            if let Some(idx) = name[..idx].find('@') {
890	                return (Some(&name[..idx - 1]), &name[idx..]);
891	            }
892	
893	            return (Some(&name[..idx]), &name[idx + 1..]);
894	        }
895	
896	        (None, name)
897	    }
