923	    /// Make a project resolver with the provided dependencies. Extras is for
924	    /// packages that are not dependencies of any other package.
925	    fn make_project<T: GitChangeDetector>(
926	        dependencies: &[(&str, &str)],
927	        extras: &[&str],
928	        package_inference: Option<PackageInference>,
929	        change_detector: T,
930	    ) -> (TempDir, super::FilterResolver<'static, T>) {
931	        let temp_folder = tempfile::tempdir().unwrap();
932	        let turbo_root = Box::leak(Box::new(
933	            AbsoluteSystemPathBuf::new(temp_folder.path().as_os_str().to_str().unwrap()).unwrap(),
934	        ));
935	
936	        let package_dirs = dependencies
937	            .iter()
938	            .flat_map(|(a, b)| vec![a, b])
939	            .chain(extras.iter())
940	            .collect::<HashSet<_>>();
941	
942	        let dependencies =
943	            dependencies
944	                .iter()
945	                .fold(HashMap::<&str, Vec<&str>>::new(), |mut acc, (k, v)| {
946	                    let k = get_name(k).1;
947	                    let v = get_name(v).1;
948	                    acc.entry(k).or_default().push(v);
949	                    acc
950	                });
951	
952	        let package_jsons = package_dirs
953	            .iter()
954	            .map(|package_path| {
955	                let (_, name) = get_name(package_path);
956	                (
957	                    turbo_root.join_unix_path(
958	                        RelativeUnixPathBuf::new(format!("{package_path}/package.json")).unwrap(),
959	                    ),
960	                    PackageJson {
961	                        name: Some(Spanned::new(name.to_string())),
962	                        dependencies: dependencies.get(name).map(|v| {
963	                            v.iter()
964	                                .map(|name| (name.to_string(), "*".to_string()))
965	                                .collect()
966	                        }),
967	                        ..Default::default()
968	                    },
969	                )
970	            })
971	            .collect::<HashMap<_, _>>();
972	
973	        for package_dir in package_jsons.keys() {
974	            package_dir.ensure_dir().unwrap();
975	        }
976	
977	        let graph = {
978	            let rt = tokio::runtime::Builder::new_current_thread()
979	                .enable_all()
980	                .build()
981	                .unwrap();
982	            rt.block_on(
983	                PackageGraph::builder(turbo_root, Default::default())
984	                    .with_package_discovery(MockDiscovery)
985	                    .with_package_jsons(Some(package_jsons))
986	                    .build(),
987	            )
988	            .unwrap()
989	        };
990	
991	        let pkg_graph = Box::leak(Box::new(graph));
992	
993	        let resolver = FilterResolver::<'static>::new_with_change_detector(
994	            pkg_graph,
995	            turbo_root,
996	            package_inference,
997	            change_detector,
998	        );
999	
1000	        // TempDir's drop implementation will mark the folder as ready for cleanup
1001	        // which can lead to non-deterministic test results if the folder is removed
1002	        // before the test finishes.
1003	        (temp_folder, resolver)
1004	    }
