1520	    impl<'a> GitChangeDetector for TestChangeDetector<'a> {
1521	        fn changed_packages(
1522	            &self,
1523	            from: Option<&str>,
1524	            to: Option<&str>,
1525	            _include_uncommitted: bool,
1526	            _allow_unknown_objects: bool,
1527	            _merge_base: bool,
1528	        ) -> Result<HashMap<PackageName, PackageInclusionReason>, ResolutionError> {
1529	            Ok(self
1530	                .0
1531	                .get(&(from.expect("expected base branch"), to))
1532	                .map(|h| h.to_owned())
1533	                .expect("unsupported range"))
1534	        }
1535	    }
