1537	    /// Creates a package graph for testing PackageInference::calculate
1538	    fn make_package_graph(
1539	        package_paths: &[&str],
1540	    ) -> (TempDir, &'static AbsoluteSystemPathBuf, PackageGraph) {
1541	        let temp_folder = tempfile::tempdir().unwrap();
1542	        let turbo_root = Box::leak(Box::new(
1543	            AbsoluteSystemPathBuf::new(temp_folder.path().as_os_str().to_str().unwrap()).unwrap(),
1544	        ));
1545	
1546	        let package_jsons = package_paths
1547	            .iter()
1548	            .map(|package_path| {
1549	                let (_, name) = get_name(package_path);
1550	                (
1551	                    turbo_root.join_unix_path(
1552	                        RelativeUnixPathBuf::new(format!("{package_path}/package.json")).unwrap(),
1553	                    ),
1554	                    PackageJson {
1555	                        name: Some(Spanned::new(name.to_string())),
1556	                        ..Default::default()
1557	                    },
1558	                )
1559	            })
1560	            .collect::<HashMap<_, _>>();
1561	
1562	        for package_dir in package_jsons.keys() {
1563	            package_dir.ensure_dir().unwrap();
1564	        }
1565	
1566	        let graph = {
1567	            let rt = tokio::runtime::Builder::new_current_thread()
1568	                .enable_all()
1569	                .build()
1570	                .unwrap();
1571	            rt.block_on(
1572	                PackageGraph::builder(turbo_root, Default::default())
1573	                    .with_package_discovery(MockDiscovery)
1574	                    .with_package_jsons(Some(package_jsons))
1575	                    .build(),
1576	            )
1577	            .unwrap()
1578	        };
1579	
1580	        (temp_folder, turbo_root, graph)
1581	    }
