1583	    /// Test that PackageInference::calculate is deterministic when invoked from
1584	    /// a directory that contains nested packages (regression test for
1585	    /// GitHub issue #11428).
1586	    ///
1587	    /// The bug was that HashMap iteration order is non-deterministic, and the
1588	    /// previous implementation would return early when it found ANY package
1589	    /// below the inference path, rather than finding the most specific one.
1590	    #[test]
1591	    fn test_package_inference_deterministic_with_nested_packages() {
1592	        // Simulate the structure from the issue:
1593	        // apps/onprem/          <- invocation directory
1594	        // apps/onprem/backend/  <- nested package
1595	        // apps/onprem/web/      <- nested package
1596	        // packages/shared/      <- unrelated package
1597	        let (_tempdir, turbo_root, graph) =
1598	            make_package_graph(&["apps/onprem/backend", "apps/onprem/web", "packages/shared"]);
1599	
1600	        // Invoke from apps/onprem (a directory containing packages)
1601	        let inference_path = AnchoredSystemPathBuf::try_from("apps/onprem").unwrap();
1602	
1603	        // Run the calculation multiple times to verify determinism
1604	        // (with the bug, different runs could give different results)
1605	        for _ in 0..10 {
1606	            let inference = PackageInference::calculate(turbo_root, &inference_path, &graph);
1607	
1608	            // We should NOT infer a specific package - we're in a directory that contains
1609	            // packages, not inside a specific package
1610	            assert!(
1611	                inference.package_name.is_none(),
1612	                "Expected no package to be inferred when running from a directory containing \
1613	                 packages, but got {:?}",
1614	                inference.package_name
1615	            );
1616	
1617	            // The directory root should be the inference path itself
1618	            assert_eq!(
1619	                inference.directory_root, inference_path,
1620	                "Expected directory_root to be the inference path"
1621	            );
1622	        }
1623	    }
