1702	    /// End-to-end test for GitHub issue #11428: running `turbo -F "{./*}^..."
1703	    /// build` from a directory containing packages should select those
1704	    /// packages' dependencies.
1705	    ///
1706	    /// This test verifies that running from apps/onprem with filter {./*}^...
1707	    /// correctly selects packages under apps/onprem/* and their dependencies,
1708	    /// rather than randomly returning 0 packages.
1709	    #[test]
1710	    fn test_issue_11428_filter_from_directory_with_nested_packages() {
1711	        // Create the structure from the issue:
1712	        // apps/onprem/backend depends on packages/shared
1713	        // apps/onprem/web depends on packages/shared
1714	        let (_tempdir, resolver) = make_project(
1715	            &[
1716	                ("apps/onprem/backend", "packages/shared"),
1717	                ("apps/onprem/web", "packages/shared"),
1718	            ],
1719	            &[],
1720	            // Simulate running from apps/onprem
1721	            Some(PackageInference {
1722	                package_name: None,
1723	                directory_root: AnchoredSystemPathBuf::try_from("apps/onprem").unwrap(),
1724	            }),
1725	            TestChangeDetector::new(&[]),
1726	        );
1727	
1728	        // The filter {./*}^... means:
1729	        // - {./*} = packages matching "./*" relative to inference directory
1730	        //   (apps/onprem/*)
1731	        // - ^... = exclude self, include dependencies
1732	        //
1733	        // So this should select: packages/shared (dependency of backend and web)
1734	        // but NOT backend or web themselves (^ excludes self)
1735	        let selector = TargetSelector::from_str("{./*}^...").unwrap();
1736	        let packages = resolver.get_filtered_packages(vec![selector]).unwrap();
1737	
1738	        // We should get the dependencies of apps/onprem/* packages
1739	        // which is packages/shared
1740	        assert!(
1741	            !packages.is_empty(),
1742	            "Expected to find packages, but got none. This is the bug from issue #11428!"
1743	        );
1744	
1745	        assert!(
1746	            packages.contains_key(&PackageName::from("shared")),
1747	            "Expected 'shared' to be selected as a dependency. Got: {:?}",
1748	            packages.keys().collect::<Vec<_>>()
1749	        );
1750	
1751	        // backend and web should NOT be included (^ excludes self)
1752	        assert!(
1753	            !packages.contains_key(&PackageName::from("backend")),
1754	            "backend should be excluded due to ^ in filter"
1755	        );
1756	        assert!(
1757	            !packages.contains_key(&PackageName::from("web")),
1758	            "web should be excluded due to ^ in filter"
1759	        );
1760	    }
