33	#[derive(Debug, Default, PartialEq, Clone)]
34	pub struct GitRange {
35	    pub from_ref: Option<String>,
36	    pub to_ref: Option<String>,
37	    pub include_uncommitted: bool,
38	    // Allow unknown objects to be included in the range, without returning an error.
39	    // this is useful for shallow clones where objects may not exist.
40	    // When this happens, we assume that everything has changed.
41	    pub allow_unknown_objects: bool,
42	    // Calculate diff between merge base of the two refs and the second ref
43	    // (this is usually what you want for detecting changes)
44	    pub merge_base: bool,
45	}
