47	/// A parsed target selector from a filter string.
48	#[derive(Debug, Default, PartialEq, Clone)]
49	pub struct TargetSelector {
50	    pub include_dependencies: bool,
51	    pub match_dependencies: bool,
52	    pub include_dependents: bool,
53	    pub exclude: bool,
54	    pub exclude_self: bool,
55	    pub follow_prod_deps_only: bool,
56	    pub parent_dir: Option<AnchoredSystemPathBuf>,
57	    pub name_pattern: String,
58	    pub git_range: Option<GitRange>,
59	    pub raw: String,
60	}
