62	impl FromStr for TargetSelector {
63	    type Err = InvalidSelectorError;
64	
65	    fn from_str(raw_selector: &str) -> Result<Self, Self::Err> {
66	        let selector = raw_selector.strip_prefix('!');
67	        let (exclude, selector) = match selector {
68	            Some(selector) => (true, selector),
69	            None => (false, raw_selector),
70	        };
71	
72	        let mut exclude_self = false;
73	        let include_dependencies = selector.strip_suffix("...");
74	
75	        let (include_dependencies, selector) = if let Some(selector) = include_dependencies {
76	            (
77	                true,
78	                if let Some(selector) = selector.strip_suffix('^') {
79	                    exclude_self = true;
80	                    selector
81	                } else {
82	                    selector
83	                },
84	            )
85	        } else {
86	            (false, selector)
87	        };
88	
89	        let include_dependents = selector.strip_prefix("...");
90	        let (include_dependents, selector) = if let Some(selector) = include_dependents {
91	            (
92	                true,
93	                if let Some(selector) = selector.strip_prefix('^') {
94	                    exclude_self = true;
95	                    selector
96	                } else {
97	                    selector
98	                },
99	            )
100	        } else {
101	            (false, selector)
102	        };
103	
104	        // We explicitly allow empty git ranges so we can return a more targeted error
105	        // below
106	        let captures = SELECTOR_REGEX.captures(selector);
107	
108	        let captures = match captures {
109	            Some(captures) => captures,
110	            None => {
111	                return if let Some(relative_path) = is_selector_by_location(selector) {
112	                    Ok(TargetSelector {
113	                        exclude,
114	                        include_dependencies,
115	                        include_dependents,
116	                        parent_dir: Some(relative_path?),
117	                        raw: raw_selector.to_string(),
118	                        ..Default::default()
119	                    })
120	                } else {
121	                    Ok(TargetSelector {
122	                        exclude,
123	                        exclude_self,
124	                        include_dependencies,
125	                        include_dependents,
126	                        name_pattern: selector.to_string(),
127	                        raw: raw_selector.to_string(),
128	                        ..Default::default()
129	                    })
130	                };
131	            }
132	        };
133	
134	        let mut pre_add_dependencies = false;
135	
136	        let name_pattern = captures
137	            .name("name")
138	            .map_or(String::new(), |m| m.as_str().to_string());
139	
140	        let mut parent_dir = None;
141	
142	        if let Some(directory) = captures.name("directory") {
143	            let directory = directory.as_str().to_string();
144	            if directory.is_empty() {
145	                return Err(InvalidSelectorError::EmptyPathSpecification);
146	            } else {
147	                let clean_directory = path_clean::clean(std::path::Path::new(directory.as_str()))
148	                    .into_os_string()
149	                    .into_string()
150	                    .expect("directory was valid utf8 before cleaning");
151	                parent_dir = Some(
152	                    AnchoredSystemPathBuf::try_from(clean_directory.as_str())
153	                        .map_err(|_| InvalidSelectorError::InvalidAnchoredPath(directory))?,
154	                );
155	            }
156	        }
157	
158	        let git_range = if let Some(commits) = captures.name("commits") {
159	            let commits_str = if let Some(commits) = commits.as_str().strip_prefix("...") {
160	                if parent_dir.is_none() && name_pattern.is_empty() {
161	                    return Err(InvalidSelectorError::CantMatchDependencies);
162	                }
163	                pre_add_dependencies = true;
164	                commits
165	            } else {
166	                commits.as_str()
167	            };
168	
169	            // strip the square brackets
170	            let commits_str = commits_str
171	                .strip_prefix('[')
172	                .and_then(|s| s.strip_suffix(']'))
173	                .expect("regex guarantees square brackets");
174	            if commits_str.is_empty() {
175	                return Err(InvalidSelectorError::InvalidGitRange(
176	                    commits_str.to_string(),
177	                ));
178	            }
179	
180	            let git_range = if let Some((a, b)) = commits_str.split_once("...") {
181	                if a.is_empty() || b.is_empty() {
182	                    return Err(InvalidSelectorError::InvalidGitRange(
183	                        commits_str.to_string(),
184	                    ));
185	                }
186	                GitRange {
187	                    from_ref: Some(a.to_string()),
188	                    to_ref: Some(b.to_string()),
189	                    include_uncommitted: false,
190	                    allow_unknown_objects: false,
191	                    merge_base: true,
192	                }
193	            } else {
194	                // If only the start of the range is specified, we assume that
195	                // we want to include uncommitted changes
196	                GitRange {
197	                    from_ref: Some(commits_str.to_string()),
198	                    to_ref: None,
199	                    include_uncommitted: true,
200	                    allow_unknown_objects: false,
201	                    merge_base: false,
202	                }
203	            };
204	            Some(git_range)
205	        } else {
206	            None
207	        };
208	
209	        Ok(TargetSelector {
210	            git_range,
211	            exclude,
212	            exclude_self,
213	            include_dependencies,
214	            include_dependents,
215	            match_dependencies: pre_add_dependencies,
216	            name_pattern,
217	            parent_dir,
218	            raw: raw_selector.to_string(),
219	            ..Default::default()
220	        })
221	    }
222	}
