224	/// Errors when parsing target selectors.
225	#[derive(Debug, Error, PartialEq)]
226	pub enum InvalidSelectorError {
227	    #[error("cannot use match dependencies without specifying either a directory or package")]
228	    CantMatchDependencies,
229	    #[error("invalid anchored path: {0}")]
230	    InvalidAnchoredPath(String),
231	    #[error("empty path specification")]
232	    EmptyPathSpecification,
233	    #[error("invalid git range selector: {0}")]
234	    InvalidGitRange(String),
235	
236	    #[error("selector \"{0}\" must have a reference, directory, or name pattern")]
237	    InvalidSelector(String),
238	}
239	
240	/// checks if the selector is a filesystem path
241	pub fn is_selector_by_location(
242	    raw_selector: &str,
243	) -> Option<Result<AnchoredSystemPathBuf, InvalidSelectorError>> {
244	    let exact_matches = [".", ".."];
245	    let prefixes = ["./", ".\\", "../", "..\\"];
246	
247	    if exact_matches.contains(&raw_selector)
248	        || prefixes
249	            .iter()
250	            .any(|prefix| raw_selector.starts_with(prefix))
251	    {
252	        let cleaned_selector = path_clean::clean(std::path::Path::new(raw_selector))
253	            .into_os_string()
254	            .into_string()
255	            .expect("raw selector was valid utf8");
256	        Some(
257	            AnchoredSystemPathBuf::try_from(cleaned_selector.as_str())
258	                .map_err(|_| InvalidSelectorError::InvalidAnchoredPath(raw_selector.to_string())),
259	        )
260	    } else {
261	        None
262	    }
263	}
