297	    #[test_case("{foo}...[master]", TargetSelector { raw: "{foo}...[master]".to_string(), git_range: Some(GitRange { from_ref: Some("master".to_string()), to_ref: None, include_uncommitted: true, ..Default::default() }), parent_dir: Some(AnchoredSystemPathBuf::try_from("foo").unwrap()), match_dependencies: true, ..Default::default() }; " curly brackets foo...[master]")]
298	    #[test_case("...@repo/pkg[master]", TargetSelector { raw: "...@repo/pkg[master]".to_string(), git_range: Some(GitRange { from_ref: Some("master".to_string()), to_ref: None, include_uncommitted: true, ..Default::default() }), name_pattern: "@repo/pkg".to_string(), include_dependents: true, ..Default::default() }; "gh 9096")]
299	    fn parse_target_selector(raw_selector: &str, want: TargetSelector) {
300	        let result = TargetSelector::from_str(raw_selector);
301	
302	        match result {
303	            Ok(got) => {
304	                assert_eq!(
305	                    got, want,
306	                    "ParseTargetSelector() = {:?}, want {:?}",
307	                    got, want
308	                );
309	            }
310	            Err(e) => {
311	                panic!("ParseTargetSelector() error = {:?}", e)
312	            }
313	        }
314	    }
315	
316	    #[test_case("{}" ; "curly brackets")]
317	    #[test_case("......[master]" ; "......[master]")]
318	    #[test_case("[]" ; "empty git range")]
319	    #[test_case("[...some-ref]" ; "missing git range start")]
320	    #[test_case("[some-ref...]" ; "missing git range end")]
321	    #[test_case("[...]" ; "missing entire git range")]
322	    fn parse_target_selector_invalid(raw_selector: &str) {
323	        let result = TargetSelector::from_str(raw_selector);
324	
325	        match result {
326	            Ok(_got) => {
327	                panic!("expected error when parsing {}", raw_selector);
328	            }
